window.__QUIZ_DATA__=[{"id":"theory>Biology>2007>1>a","subject":"Biology","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"In a tabular form, distinguish between tropic movements and nastic movements.","images":[],"marking_scheme":"Difference between Tropic and Nostic  Movements  Tropic Movement Nastic Movement1. It is a growth movement. It is not a growth movement2. Respond to stimulus Responds to diffuse stimulus3. Not reversible Reversible4. Slow responseFast response5. Not due to cell turgor Due to changes in cell turgor6. Directional  Non-directional  Note: When you are asked to differentiate, you are expected to tabulate.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2007>1>b","subject":"Biology","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"Explain how light brings about tropic movement in the stem and root of a flowering plant.","images":[],"marking_scheme":"A. STEM unilateral light fall on the stem, the auxin/growth hormone/It is displaced from the lighted to the dark-side, the increase in the concentration of auxin in the dark-side of the stem increases growth on that side, causing the stem to bend towards the light/positive phototropism.    B. ROOT  The auxin is displaced from the lighted side to the dark side. The increase in auxin concentration retards growth on the dark side, causing the root to bend away from the light/negative phototropism.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2007>1>c","subject":"Biology","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"CONCEPT OF LIVING : IRRITABILITY AS A BASIC CHARACTERISTIC OF PROTOPLASM","question":"What would be observed when a growing seedling is placed horizontally?","images":[],"marking_scheme":"Horizontally Placed Seedling  In a horizontally placed seedling,  - Shoot bends upward  - There is negative geotropism/positive phototropism.  - Root bonds downward  - There is positive geotropism/negative phototropism","marks":"4","difficulty":"1"},{"id":"theory>Biology>2007>1>d","subject":"Biology","year":"2007","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"State five functions of the pituitary gland.","images":[],"marking_scheme":"Functions of Pituitary Gland  The function of the pituitary gland include:  1. Stimulates growth  2. Stimulates the production of sex hormones  3. Stimulates the production of anti-diuretic hormone  4. Induces milk production  5. Controls egg and sperm production  6. Induces birth by contraction of uterine  7. Stimulates protein synthesis  8. Produces hormones which control other endocrine glands.","marks":"5","difficulty":"3"},{"id":"theory>Biology>2007>1>e","subject":"Biology","year":"2007","type":"Theory","sub_label":"e","group":"CLOSENESS","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"State two differences between growth in plants and growth in animals.","images":[],"marking_scheme":"Differences between growth in plants and animals   Growth in plantsGrowth in animals1. Unlimited growthLimited growth2. No fixed number of organsFixed number of organs3. Limited to specific region Non-restricted","marks":"3","difficulty":"2"},{"id":"theory>Biology>2007>2>a","subject":"Biology","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"What is a balanced diet?","images":[],"marking_scheme":"Balanced diet: A diet is said to be balanced when it contains all six food classes in the right proportion to meet the body's requirement for growth, repair and maintenance.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2007>2>b","subject":"Biology","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Name the classes of food stating the importance of any two to the human diet.","images":[],"marking_scheme":"Classes of food  The classes of food include:  1. Protein  2. Carbohydrates  3. Vitamins  4. Minerals  5. Fats and Oil  6. Water    Importance of the Food Classes  Food ClassImportanceCarbohydratesIt supplies energy, i.e energy-givingProtein Growth/replacement/repair of worn-out parts and tissuesFats and Oil Energy source/formation of adipose tissue for insulationVitaminsFor proper functioning and maintenance of the body.Mineral Salts Play specific roles in metabolic processes/ maintenance of the bodyWater Aids (1) digestion of food   (2) Medium for various metabolic processes.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2007>2>c>i","subject":"Biology","year":"2007","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"In a tabular form, state the source, substrate and end products of the enzyme ptyalin","images":[],"marking_scheme":"EnzymeSourceSubstrateFood ProductPtyalinSalivary glandCooked Starch Maltose","marks":"5","difficulty":"3"},{"id":"theory>Biology>2007>2>c>ii","subject":"Biology","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"In a tabular form, state the source, substrate and end products of the enzyme pepsin","images":[],"marking_scheme":"EnzymeSourceSubstrateFood ProductPepsinGastric glandProteinPeptones/polypeptides","marks":"5","difficulty":"3"},{"id":"theory>Biology>2007>2>c>iii","subject":"Biology","year":"2007","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"In a tabular form, state the source, substrate and end products of the enzyme lipase","images":[],"marking_scheme":"EnzymeSourceSubstrateFood ProductLipasePancreasFats/Oil/LipidsFatty acid and Glycerol","marks":"5","difficulty":"3"},{"id":"theory>Biology>2007>3>a>i","subject":"Biology","year":"2007","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Define the term gene","images":[],"marking_scheme":"Genes: Are hereditary units/materials, located on the chromosomes through which characters are transmitted from parents to offspring.","marks":"2","difficulty":"1"},{"id":"theory>Biology>2007>3>a>ii","subject":"Biology","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Define the term gene mutation","images":[],"marking_scheme":"Gene mutation: This is a spontaneous/sudden/unpredictable change in an individual gene which is persistent/permanent/irreversible/heritable.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2007>3>b>i","subject":"Biology","year":"2007","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL THEORY","question":"Name two structures each of plants and animals where mitosis take place.","images":[],"marking_scheme":"Mitosis in Plants  The structures involved in plants during mitosis include:  1. Root tip   2. Root apex  3. Stem tip  4. Cambium  5. Meristem  6. Apex    Mitosis in animals  The structures involved in animals during mitosis include:  1. Skin   2. Damaged tissue  3. Bone marrow  4. Somatio cells  5. Wounded area of the body.","marks":"3","difficulty":"2"},{"id":"theory>Biology>2007>3>b>ii","subject":"Biology","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : CELL THEORY","question":"Name two structures each of plants and animals where meiosis take place.","images":[],"marking_scheme":"Meiosis in plants  The structures involved in plants during meiosis include:  1. Ovaries   2. Anthers    Meiosis in animals  The structures involved in animals during meiosis include:  1. Ovaries   2. Testes","marks":"2","difficulty":"2"},{"id":"theory>Biology>2007>3>c","subject":"Biology","year":"2007","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : RELEVANCE OF BIOLOGY TO AGRICULTURE","question":"State four advantages a farmer may hope to derive in cross breeding two different breeds of cows.","images":[],"marking_scheme":"Advantages of Cross-breeding  1. Increased milk production  2. Increased meat production  3. Resistance to diseases in the offspring  4. Early maturity  5. Increased fecundity/reproductive capacity","marks":"5","difficulty":"3"},{"id":"theory>Biology>2007>3>d","subject":"Biology","year":"2007","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"State three applications of the knowledge of genetics in medicine.","images":[],"marking_scheme":"Applications of Genetics to Medicine  1. Prevention of hereditary disease  2. Determination of the paternity of a child by use of DNA/blood group  3. Blood transfusion  4. Production of insulin (to treat diabetes)","marks":"5","difficulty":"2"},{"id":"theory>Biology>2007>4>a>i","subject":"Biology","year":"2007","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"What is pollution?","images":[],"marking_scheme":"Pollution is the discharge of harmful (toxic substances) substance into the environment in quantities which are harmful to life, as a result of the activities of humans","marks":"5","difficulty":"1"},{"id":"theory>Biology>2007>4>a>ii","subject":"Biology","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"State four pollutants of water.","images":[],"marking_scheme":"Pollutants of water include:  1. Domestic waste e.g sewage  2. Industrial waste e.g detergents, dyes  3. Oil spillage  4. Agricultural wastes","marks":"5","difficulty":"2"},{"id":"theory>Biology>2007>4>b","subject":"Biology","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECOLOGICAL MANAGEMENT : POLLUTION OF THE ATMOSPHERE","question":"Describe the effects of each of the pollutants named on aquatic organisms.","images":[],"marking_scheme":"Effects of pollutants on aquatic organisms  Domestic waste e.g Sewage  - Bacterial breakdown of sewage reduces dissolved oxygen in water/eutrophication, aquatic animals suffocate and die.  - Rapid growth of aquatic plants due to mineral rich sewage reduces light penetration and photosynthesis.  - Contaminated sewage spread disease-causing organisms.    Industrial Wastes e.g Detergent, dyes  - Are poisonous to aquatic organisms  - Detergents from foam on the water surface reduces light penetration and photosynthesis reduces surface tension making floating animals to sink  - Dyes from textile factories reduces light penetration    Agricultural Waste e.g fertilizers  - This may accumulate to toxic levels, thereby poisoning aquatic organisms  - Fertilizer residues stimulate growth of aquatic plant which form a dense mat on the surface of the water.    Oil spillage  - Oil reduces surface tension of water, causing floating animals to sink.  - Animals die from lack of oxygen    Hot water  - Kills living organism  - Upset the balance of the ecosystem  - Hot water increases the water temperature thereby reducing the oxygen content and leading to death.","marks":"10","difficulty":"3"},{"id":"theory>Biology>2007>5>a>i","subject":"Biology","year":"2007","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"List five birth control methods.","images":[],"marking_scheme":"Birth Control Methods  1. Withdrawal methods/coitus-interruptus  2. Intra-Uterine Device (IUD)/ coil / loop  3. Rhythm / Safe period / Calender method  4. Pills/Oral Contraceptive  5. Tubal ligation/Female sterilization  6. Vasectomy/Male sterilization  7. Diaphragm/Cervical cap  8. Male condom/ sheat/ female condom  9. (Depo-provera) injections - Abstinence","marks":"8","difficulty":"2"},{"id":"theory>Biology>2007>5>a>ii","subject":"Biology","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"State five reasons why family planning is important to a nation.","images":[],"marking_scheme":"Importance of Family Planning  1. Promotes maternal / child health  2. Prevents population explosion  3. Reduces maternal / infant mortality rates   4. Makes child spacing possible  5. Prevents indiscriminate abortion  6. Increases standard of living.","marks":"6","difficulty":"1"},{"id":"theory>Biology>2007>5>b","subject":"Biology","year":"2007","type":"Theory","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Make a drawing 8 to 10 cm long of the reproductive system of a human female and label fully.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"7","difficulty":"3"},{"id":"theory>Biology>2007>6>a","subject":"Biology","year":"2007","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Describe the characteristic features of the vegetation of the tropical rain forest.","images":[],"marking_scheme":"Vegetation of Tropical Forest  - Vegetation divided into 5 layers/ strata ground layer of non woody plants/ lichen / ferns/ grasses   - Lower layer of shade-loving dwarf/tree/palms/shrubs   - Middle layer of small trees with elongated narrow crowns  - Upper layer of tall trees whose crowns form a continuous canopy  - The emergent trees come above the canopy at intervals  - The forest is very rich in species  - Trees have straight/slender trunks with branches mostly near at the top  - Most of the trees are evergreen  - Most of the trees have buttress and prop roots that support tall stems  - The leaves of the trees tend to be broad  - The flowers of those trees are usually small  - Epiphytes, climbers and parasitic plants are numerous and form close associations with the domestic plants.   - Epiphytes have adaptations for storing water and absorbing moisture from the air.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2007>6>b","subject":"Biology","year":"2007","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BASIC ECOLOGICAL CONCEPTS : HABITATS","question":"Name two types of savanna found in Nigeria giving one example in each case of a town where they occur.","images":[],"marking_scheme":"Types of Savanna and Area found  Guinea Savanna - Kaduna, Ilorin, Bida  Sahel Savanna - Maiduguri  Sudan Savanna - Kani, Borno, Sokoto, Adamawa, Taraba, Bauchi","marks":"5","difficulty":"2"},{"id":"theory>Biology>2007>6>c>i","subject":"Biology","year":"2007","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Describe briefly three ways each by which animals in arid habitats are adapted to drought.","images":[],"marking_scheme":"Drought  Animals in arid habitats are adapted to drought in the following ways   - Use of metabolic water  - Production of concentrated water/Urine  - Living in burrows/hibernation  - Thick scales/skin to prevent water loss by evaporation.","marks":"5","difficulty":"2"},{"id":"theory>Biology>2007>6>c>ii","subject":"Biology","year":"2007","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Describe briefly three ways each by which animals in arid habitats are adapted to high temperatures.","images":[],"marking_scheme":"Temperature (High)  Animals in arid habitats are adapted to high temperature in the following ways  - Seeking shade to keep cool, nocturnal life  - Living in burrows/underground tunnels where temperature is low  - Restricting activities to cooler period.","marks":"5","difficulty":"2"}];